            return e
        }
    }
    
    /**
     */
    private fun _shiftPlaybackRangeToApi(e: com.omnifret.gplayer.synth.PlaybackRange?): com.omnifret.gplayer.synth.PlaybackRange?{
        if (e == null)
        {
            return e
        }
        var tickShift: Double = this.midiTickShift
        if (tickShift > 0)
        {
            var range: com.omnifret.gplayer.synth.PlaybackRange = com.omnifret.gplayer.synth.PlaybackRange()
            range.startTick = e!!.startTick - tickShift
            range.endTick = e!!.endTick - tickShift
            return range
        }
        else 
        {
            return e!!
        }
    }
    
    /**
     */
    private fun _shiftPlaybackRangeToPlayer(e: com.omnifret.gplayer.synth.PlaybackRange?): com.omnifret.gplayer.synth.PlaybackRange?{
        if (e == null)
        {
            return e
        }
        var tickShift: Double = this.midiTickShift
        if (tickShift > 0)
