            return e!!
        }
    }
    
    /**
     */
    private fun _shiftPositionChangedEventArgsToApi(e: com.omnifret.gplayer.synth.PositionChangedEventArgs?): com.omnifret.gplayer.synth.PositionChangedEventArgs?{
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(e)))
        {
            return e
        }
        var tickShift: Double = this.midiTickShift
        return if(tickShift > 0)  com.omnifret.gplayer.synth.PositionChangedEventArgs(e!!.currentTime, 
        e!!.endTime, 
        e!!.currentTick - tickShift, 
        e!!.endTick - tickShift, 
        e!!.isSeek, 
        e!!.originalTempo, 
        e!!.modifiedTempo) else e!!
    }
    
    /**
     */
    private fun _shiftTickToApi(tickPosition: Double): Double{
        return tickPosition - this.midiTickShift
    }
    
    /**
